// Method 1: Create by specifying size (initialized with default values)
int[] scores = new int[5];
// → [0, 0, 0, 0, 0]   Note: Default value for int is 0

// Method 2: Create by specifying initial values
String[] fruits = {"Apple", "Mandarin", "Grape"};

// Method 3: new keyword + initial values
double[] prices = new double[]{100.0, 250.5, 380.0};

// Default values for each type
// int    → 0
// double → 0.0
// boolean → false
// char   → '\u0000'
// String(ReferenceType) → null

int[] nums = {10, 20, 30, 40, 50};

// Getting elements(0-based indexing)
System.out.println(nums[0]); // 10(First element)
System.out.println(nums[4]); // 50(Last element)

// Changing elements
nums[2] = 99;
System.out.println(nums[2]); // 99

// Array length
System.out.println(nums.length); // 5  Note: () is not needed

// Get the last element
System.out.println(nums[nums.length - 1]); // 50

// Out of range access → ArrayIndexOutOfBoundsException
// System.out.println(nums[5]); // Runtime Error!

String[] names = {"Taro", "Hanako", "Jiro"};

// Standard for loop
for (int i = 0; i < names.length; i++) {
    System.out.println((i + 1) + ": " + names[i]);
}
// 1: Taro  2: Hanako  3: Jiro

// Enhanced for loop(for-each)- Process all elements sequentially
for (String name : names) {
    System.out.println("Hello, " + name + "");
}

// Calculating total and average
int[] scores = {85, 92, 78, 95, 88};
int sum = 0;
for (int score : scores) {
    sum += score;
}
double avg = (double) sum / scores.length;
System.out.println("Average: " + avg); // Average: 87.6

