// Two-dimensional array declaration and initialization
int[][] matrix = {
    {1, 2, 3},   // 0Line
    {4, 5, 6},   // 1Line
    {7, 8, 9}    // 2Line
};

// Element access: matrix[ row][column]
System.out.println(matrix[0][0]); // 1(Row 0, Column 0)
System.out.println(matrix[1][2]); // 6(Row 1, Column 2)
System.out.println(matrix[2][1]); // 8(Row 2, Column 1)

//  row count and column count
System.out.println(matrix.length);    // 3( row count)
System.out.println(matrix[0].length); // 3(Column count of row 0)

// Traversing all elements (nested loop)
for (int i = 0; i < matrix.length; i++) {
    for (int j = 0; j < matrix[i].length; j++) {
        System.out.print(matrix[i][j] + " ");
    }
    System.out.println();
}

import java.util.Arrays;

int[] nums = {5, 2, 8, 1, 9, 3};

// Sort (ascending)
Arrays.sort(nums);
System.out.println(Arrays.toString(nums));
// [1, 2, 3, 5, 8, 9]

// String representation
String[] fruits = {"Apple", "Mandarin", "Grape"};
System.out.println(Arrays.toString(fruits));
// [Apple, Mandarin, Grape]

// Copying an array
int[] original = {10, 20, 30};
int[] copy = Arrays.copyOf(original, 5);
System.out.println(Arrays.toString(copy));
// [10, 20, 30, 0, 0]   Note: Expanded with 0

// Range copy
int[] sub = Arrays.copyOfRange(original, 0, 2);
System.out.println(Arrays.toString(sub)); // [10, 20]

// Fill all elements with specified value
int[] filled = new int[5];
Arrays.fill(filled, 99);
System.out.println(Arrays.toString(filled));
// [99, 99, 99, 99, 99]

// Array comparison
int[] a = {1, 2, 3};
int[] b = {1, 2, 3};
System.out.println(a == b);             // false(ReferenceComparison)
System.out.println(Arrays.equals(a, b)); // true(Content comparison)

import java.util.Arrays;

// Binary search (Array must be sorted!)
int[] sorted = {10, 20, 30, 40, 50};
int idx = Arrays.binarySearch(sorted, 30);
System.out.println(idx); // 2(Index)

int notFound = Arrays.binarySearch(sorted, 25);
System.out.println(notFound); // Negative value(not found)

// Partial sort (fromIndex, toIndex)
int[] data = {5, 3, 8, 1, 9, 2};
Arrays.sort(data, 1, 4); // Sort index 1~3
System.out.println(Arrays.toString(data));
// [5, 1, 3, 8, 9, 2]  Note: Only index 1-3 sorted

// Two-dimensional array string representation
int[][] m = {{1, 2}, {3, 4}};
System.out.println(Arrays.deepToString(m));
// [[1, 2], [3, 4]]

// Two-dimensional array comparison
int[][] m2 = {{1, 2}, {3, 4}};
System.out.println(Arrays.deepEquals(m, m2)); // true

