import java.util.ArrayList;
import java.util.List;

List<String> fruits = new ArrayList<>();

// Add
fruits.add("Apple");           // Add to end
fruits.add("Mandarin");
fruits.add("Grape");
fruits.add(1, "Banana");         // Insert at index 1
