String first = fruits.get(0);    // "Apple"
int size = fruits.size();        // 4

// Modify
fruits.set(0, "Strawberry");         // Replace at index 0
// [Strawberry, Banana, Mandarin, Grape]

// Search
boolean has = fruits.contains("Mandarin"); // true
int idx = fruits.indexOf("Banana");     // 1

// Delete
fruits.remove("Mandarin");         // Delete by value
fruits.remove(0);                // Delete by index

// Loop
for (String f : fruits) {
    System.out.println(f);
}

// Empty check
System.out.println(fruits.isEmpty()); // false
fruits.clear();                       // Delete all
System.out.println(fruits.isEmpty()); // true

import java.util.ArrayList;
import java.util.LinkedList;
import java.util.List;

// ArrayList: Internally uses array → Fast random access
List<String> arrayList = new ArrayList<>();
arrayList.add("A");
arrayList.add("B");
arrayList.add("C");
String b = arrayList.get(1); // O(1) Fast!

// LinkedList: Linked nodes → Fast insert/delete at beginning/middle
List<String> linkedList = new LinkedList<>();
linkedList.add("X");
linkedList.add("Y");
linkedList.add("Z");
linkedList.add(0, "W"); // O(1) Fast insertion at head!

// Usage guidelines:
//  Heavy random access → ArrayList (most cases)
//  Frequent add/delete at head → LinkedList
//  When in doubt, choose ArrayList

