import java.util.HashSet;
import java.util.Set;

Set<String> colors = new HashSet<>();

// Add
colors.add("Red");
colors.add("Blue");
colors.add("Green");
colors.add("Red"); // Duplicates are ignored

System.out.println(colors.size());  // 3(Duplicates count as 1)
System.out.println(colors);         // [Red, Blue, Green](Order is not guaranteed)

// Existence check
System.out.println(colors.contains("Blue")); // true

// Delete
colors.remove("Green");

// Loop
for (String c : colors) {
    System.out.println(c);
}

// Technique to remove duplicates from list
List<String> list = List.of("A", "B", "A", "C", "B");
Set<String> unique = new HashSet<>(list);
System.out.println(unique); // [A, B, C]

import java.util.*;

// TreeSet: Elements are sorted (natural order)
Set<Integer> treeSet = new TreeSet<>();
treeSet.add(30);
treeSet.add(10);
treeSet.add(20);
System.out.println(treeSet); // [10, 20, 30] Always in sorted order

// LinkedHashSet: Preserves insertion order
Set<String> linked = new LinkedHashSet<>();
linked.add("C");
linked.add("A");
linked.add("B");
System.out.println(linked); // [C, A, B] Maintains insertion order

// Usage guidelines:
// HashSet     → Fastest. When order is not needed (most cases)
// TreeSet     → When sorted order is needed
// LinkedHashSet → When you want to preserve insertion order

// Set operations
Set<String> set1 = new HashSet<>(Set.of("A", "B", "C"));
Set<String> set2 = new HashSet<>(Set.of("B", "C", "D"));

// Intersection (common elements)
set1.retainAll(set2);
System.out.println(set1); // [B, C]

