import java.util.HashMap;
import java.util.Map;

Map<String, Integer> scores = new HashMap<>();

// Adding/Updating values
scores.put("Taro", 85);
scores.put("Hanako", 92);
scores.put("Jiro", 78);
scores.put("Taro", 90);  // Same key is overwritten

// Getting values
int taro = scores.get("Taro");  // 90
System.out.println(scores.get("Shiro")); // null(Does not exist)

// Get with default value
int value = scores.getOrDefault("Shiro", 0); // 0

// Existence check
System.out.println(scores.containsKey("Hanako")); // true
System.out.println(scores.containsValue(92));   // true

// Size
System.out.println(scores.size()); // 3

// Delete
scores.remove("Jiro");

// Loop (EntrySet)
for (Map.Entry<String, Integer> e : scores.entrySet()) {
    System.out.println(e.getKey() + ": " + e.getValue());
}

import java.util.*;

Map<String, Integer> map = new HashMap<>();
map.put("A", 1);
map.put("B", 2);

// putIfAbsent: Add only if key does not exist
map.putIfAbsent("A", 99); // "A" already exists, no change
map.putIfAbsent("C", 3);  // "C" to add

// merge: Combine existing and new value
map.merge("A", 10, Integer::sum); // A: 1 + 10 = 11

// forEach
map.forEach((k, v) -> System.out.println(k + "=" + v));

// KeySet/Value Collection
Set<String> keys = map.keySet();      // [A, B, C]
Collection<Integer> vals = map.values(); // [11, 2, 3]

// TreeMap: Keys are sorted
Map<String, Integer> treeMap = new TreeMap<>();
treeMap.put("banana", 200);
treeMap.put("apple", 100);
treeMap.put("cherry", 300);
System.out.println(treeMap);
// {apple=100, banana=200, cherry=300} Sorted by key

