import java.util.*;

// --- Array → List ---
String[] array = {"A", "B", "C"};

// Arrays.asList: Fixed-size list (add/delete not allowed)
List<String> fixed = Arrays.asList(array);
// fixed.add("D"); // UnsupportedOperationException
fixed.set(0, "X"); // OK (modification allowed)

// Convert to mutable list (recommended)
List<String> mutable = new ArrayList<>(Arrays.asList(array));
mutable.add("D"); // OK

// Java 11+: List.of() for immutable list
List<String> immutable = List.of(array);

// --- List → Array ---
List<String> list = List.of("X", "Y", "Z");

// toArray (with type)
String[] arr = list.toArray(new String[0]);
System.out.println(Arrays.toString(arr)); // [X, Y, Z]

// Java 11+ toArray(MethodReference)
String[] arr2 = list.toArray(String[]::new);

// Autoboxing: Primitive → Wrapper(Automatic conversion)
Integer a = 100;         // int → Integer(Automatic)
Double b = 3.14;         // double → Double(Automatic)

// Unboxing: Wrapper → Primitive(Automatic conversion)
int c = a;               // Integer → int(Automatic)
double d = b;            // Double → double(Automatic)

// Using with collections
List<Integer> numbers = new ArrayList<>();
numbers.add(10);         // int → Integer(Autoboxing)
numbers.add(20);
int first = numbers.get(0); // Integer → int(Unboxing)

// Calculation also uses automatic conversion
Integer x = 10;
Integer y = 20;
int sum = x + y; // Integer → int → Calculation → int

// ⚠️ Beware of null unboxing!
Integer nullVal = null;
// int n = nullVal; // NullPointerException!

// String → NumberConversion(parseXxx)
int i = Integer.parseInt("123");         // 123
double d = Double.parseDouble("3.14");   // 3.14
long l = Long.parseLong("1000000");      // 1000000

// Number → StringConversion
String s1 = Integer.toString(123);         // "123"
String s2 = String.valueOf(123);           // "123"(Recommended)

// Constant
System.out.println(Integer.MAX_VALUE);     // 2147483647
System.out.println(Integer.MIN_VALUE);     // -2147483648
System.out.println(Double.MAX_VALUE);      // 1.7976931348623157E308

// valueOf: With cacheObjectGeneration
Integer a1 = Integer.valueOf(127);
Integer a2 = Integer.valueOf(127);
System.out.println(a1 == a2);  // true(-128~127 is cached)

Integer b1 = Integer.valueOf(128);
Integer b2 = Integer.valueOf(128);
System.out.println(b1 == b2);  // false(Outside cache range)
System.out.println(b1.equals(b2)); // true(ValueComparison)

